import{_ as o,a2 as r,y as t,B as a,b as n}from"./chunks/framework.BrfCoiDy.js";const u=JSON.parse('{"title":"🚀 Welcome!","description":"","frontmatter":{},"headers":[],"relativePath":"01-welcome.md","filePath":"01-welcome.md"}'),i={name:"01-welcome.md"};function s(l,e,c,d,h,m){return r(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="🚀-welcome" tabindex="-1">🚀 Welcome! <a class="header-anchor" href="#🚀-welcome" aria-label="Permalink to “🚀 Welcome!”">​</a></h1><p>This is the documentation for the first robotics project in the STEM department of Arcelo Memorial National High School. You may read it chronologically, or skip some parts, but reading chronologically is recommended to better understand the project.</p><p>You may stumble upon jargons and hard terms, so check out <a href="/02-definition-of-terms">Definition of terms</a>. You may read the documentation, and click on words to get their definitions as you go.</p><h4 id="have-fun" tabindex="-1">Have fun! <a class="header-anchor" href="#have-fun" aria-label="Permalink to “Have fun!”">​</a></h4><h2 id="🤖-overview" tabindex="-1">🤖 Overview <a class="header-anchor" href="#🤖-overview" aria-label="Permalink to “🤖 Overview”">​</a></h2><p><strong>Project Name</strong>: SWAGI (Stagnant Water Collector and Garden Irrigatorr) BloomBot<br><strong>Team Members</strong>: Ed Carlo P. Aparece, Fiel Franco A. Degamo, Giovanie R. Logroño <br><strong>Adviser</strong>: Jerry C. Angtud<br><strong>School Year</strong>: 2025-2026<br><strong>Research Paper</strong>: <a href="https://docs.google.com/document/d/1T_vZmyBlvhjeLJpllFRJ5p8uDwEyDlsU9Yc5tlmai6E/edit?usp=sharing" target="_blank" rel="noreferrer">SWAGI BLOOMBOT: A STAGNANT WATER ACCUMULATOR AND GARDEN IRRIGATOR </a></p><img src="'+n+'" width="300px" height="330px"> This project was designed to solve the problem of stagnant water accumulation after heavy rainfalls around the SHS and JHS building grounds in AMNHS. The robot collects water using a pump and stores it in a simple container. Another pump is then used to irrigate the stored water through a hose. A servo motor helps distribute the water evenly during irrigation. <p>The robot can move forward, backward, left, and right using four geared motors with differential steering. It uses Wi-Fi communication to connect the robot to an app on the operator’s phone for wireless control.</p><p>The system is powered by two 18650 Li-ion batteries (7.4V, 2200mAh) and can operate for about one hour or less during continuous use, based on testing.</p>',10)])])}const g=o(i,[["render",s]]);export{u as __pageData,g as default};
